const token = $('Auth Siigo').first().json.access_token;
const SH = { Authorization:'Bearer '+token, 'Partner-Id':'n8nApp' };
const SB = 'https://wavqyesyqqmawjfaztvb.supabase.co';
const KEY = '__SUPABASE_SERVICE_ROLE__';
const H = { apikey:KEY, Authorization:'Bearer '+KEY };
const http = (o) => this.helpers.httpRequest(o);

// Envoltura que NUNCA lanza: devuelve {ok,status,data}. Antes un 404 (o cualquier
// hipo de Siigo) fuera del try tumbaba la ejecucion entera.
async function safe(o, tries) {
  tries = tries || 3;
  let last = 0, msg = '';
  for (let i = 0; i < tries; i++) {
    try {
      return { ok:true, status:200, data: await http(o) };
    } catch (e) {
      msg = String((e && e.message) || e);
      const m = /\b(\d{3})\b/.exec(msg);
      last = Number((e && (e.httpCode || e.statusCode)) || (e && e.cause && e.cause.statusCode) || (m && m[1]) || 0);
      if (last === 404) return { ok:false, status:404, error:msg };   // definitivo, no reintentar
      if (i === tries - 1) return { ok:false, status:last, error:msg };
      await new Promise(r => setTimeout(r, 2000 * (i + 1)));
    }
  }
  return { ok:false, status:last, error:msg };
}

const hoy = new Date();
const desde = new Date(hoy.getTime() - 75*86400000).toISOString().slice(0,10);
const hasta = hoy.toISOString().slice(0,10);

// 1. IDs en Supabase dentro de la ventana (por fecha de factura)
const sbIds = [];
let off = 0;
while (true) {
  const r = await safe({ method:'GET', json:true, headers:H,
    url: SB + '/rest/v1/ventas_invoices?select=id&raw->>date=gte.' + desde + '&raw->>date=lte.' + hasta + '&limit=1000&offset=' + off });
  if (!r.ok) return [{ json:{ alerta:'no se pudo leer Supabase ('+r.status+') - no se borro nada', error:r.error } }];
  const arr = Array.isArray(r.data) ? r.data : [];
  for (const x of arr) sbIds.push(x.id);
  if (arr.length < 1000) break;
  off += 1000;
}

// 2. IDs vivos en Siigo (estandar + serie FV-2 exportacion).
//    Siigo tarda entre 2s y 18s por pagina y son ~30 paginas: en serie se pasaba
//    de los 300s del Code node. Se piden de a 5 en paralelo.
const live = new Set();
let paginasFallidas = 0;
const CONC = 5;

async function fetchLive(extra) {
  const url = (p) => 'https://api.siigo.com/v1/invoices?date_start=' + desde + '&date_end=' + hasta +
                     extra + '&page=' + p + '&page_size=100';
  const first = await safe({ method:'GET', json:true, headers:SH, url: url(1) });
  if (!first.ok) { paginasFallidas++; return; }
  const tot = ((first.data || {}).pagination || {}).total_results || 0;
  for (const i of ((first.data || {}).results || [])) live.add(i.id);
  const pages = [];
  for (let p = 2; p <= Math.ceil(tot / 100); p++) pages.push(p);
  for (let i = 0; i < pages.length; i += CONC) {
    const res = await Promise.all(pages.slice(i, i + CONC)
      .map(p => safe({ method:'GET', json:true, headers:SH, url: url(p) })));
    for (const r of res) {
      if (!r.ok) { paginasFallidas++; continue; }
      for (const x of ((r.data || {}).results || [])) live.add(x.id);
    }
  }
}
await fetchLive('');
await fetchLive('&document_id=30537');

// FAIL-SAFE: si no pudimos leer el listado completo, una factura viva podria
// parecer fantasma. Mejor no borrar nada que borrar una factura buena.
if (paginasFallidas > 0) {
  return [{ json:{ alerta:'fallaron '+paginasFallidas+' paginas de Siigo - no se borro nada',
                   ventana:desde+'..'+hasta, supabase:sbIds.length, vivas:live.size } }];
}

// 3. Candidatas: en Supabase pero no en la lista viva
const candidatas = sbIds.filter(id => !live.has(id));

// Cap de seguridad
if (candidatas.length > 60) {
  return [{ json:{ alerta:'DEMASIADAS CANDIDATAS ('+candidatas.length+') - no se borro nada',
                   ventana:desde+'..'+hasta, supabase:sbIds.length, vivas:live.size } }];
}

// 4. Verificar cada candidata con GET directo -> borrar SOLO si 404 confirmado
const borradas = [];
const conservadas = [];
const sinVerificar = [];
for (let i = 0; i < candidatas.length; i += CONC) {
  const lote = candidatas.slice(i, i + CONC);
  const res = await Promise.all(lote.map(id =>
    safe({ method:'GET', json:true, headers:SH, url:'https://api.siigo.com/v1/invoices/' + id })));
  for (let k = 0; k < lote.length; k++) {
    const id = lote[k], r = res[k];
    if (r.ok) { conservadas.push(id); continue; }
    if (r.status !== 404) { sinVerificar.push(id); continue; }  // duda -> no se toca
    const del = await safe({ method:'DELETE', json:true,
      headers: Object.assign({}, H, { Prefer:'return=minimal' }),
      url: SB + '/rest/v1/ventas_invoices?id=eq.' + id });
    if (del.ok) borradas.push(id); else sinVerificar.push(id);
  }
}

return [{ json: {
  ventana: desde + '..' + hasta,
  supabase: sbIds.length, vivas: live.size,
  candidatas: candidatas.length,
  borradas: borradas.length, idsBorradas: borradas,
  conservadas: conservadas.length,
  sinVerificar: sinVerificar.length, idsSinVerificar: sinVerificar
} }];

